    // Extract matrix shapes
    auto *a_storage = context->GetInputShape(0);
    auto *b_storage = context->GetInputShape(1);
    uint32_t M = static_cast<uint32_t>(a_storage->GetOriginShape().GetDim(0));
    uint32_t K = static_cast<uint32_t>(a_storage->GetOriginShape().GetDim(1));
    uint32_t N = static_cast<uint32_t>(b_storage->GetOriginShape().GetDim(1));

    // Generate cube tiling using MultiCoreMatmulTiling
    auto ascendcPlatform = platform_ascendc::PlatformAscendCManager::GetInstance();
    matmul_tiling::MultiCoreMatmulTiling cubeTilingGen(*ascendcPlatform);

    cubeTilingGen.SetDim(blockDim);
    cubeTilingGen.SetAType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND,
                           matmul_tiling::DataType::DT_FLOAT, false);
    cubeTilingGen.SetBType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND,
                           matmul_tiling::DataType::DT_FLOAT, false);
    cubeTilingGen.SetCType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND,
                           matmul_tiling::DataType::DT_FLOAT);
    cubeTilingGen.SetOrgShape(M, N, K);
    cubeTilingGen.SetShape(M, N, K);
    cubeTilingGen.SetBufferSpace(-1, -1, -1);

    TCubeTiling cubeTiling;
    if (cubeTilingGen.GetTiling(cubeTiling) != 0) {
        return ge::GRAPH_FAILED;
    }

    // Copy cubeTiling directly to tiling buffer (kernel expects TCubeTiling)
    auto *tilingBuffer = context->GetRawTilingData()->GetData();
    size_t capacity = context->GetRawTilingData()->GetCapacity();
    if (sizeof(TCubeTiling) > capacity) {
        return ge::GRAPH_FAILED;
    }
    memcpy(tilingBuffer, &cubeTiling, sizeof(TCubeTiling));
    context->GetRawTilingData()->SetDataSize(sizeof(TCubeTiling));

    // Set block dim (must be set after possibly adjusting)
    context->SetBlockDim(blockDim);

    // Workspace not needed
    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;

    return ge::GRAPH_SUCCESS;
}

